SELECT COUNT(1) FROM sys_dict_data d WHERE d.deleted = 0
AND d.dict_type_code = #{query.dictTypeCode}
AND (d.dict_label LIKE CONCAT('%', #{query.keyword}, '%') OR d.dict_value LIKE CONCAT('%', #{query.keyword}, '%'))
AND d.status = #{query.status}

SELECT 
FROM sys_dict_data d
WHERE d.deleted = 0

      AND d.dict_type_code = #{query.dictTypeCode}


      AND (d.dict_label LIKE CONCAT('%', #{query.keyword}, '%')
          OR d.dict_value LIKE CONCAT('%', #{query.keyword}, '%'))


